// GSM SIM900A Module
#include <SoftwareSerial.h>

SoftwareSerial gsm(7, 8);  // RX, TX

void setup() {
  Serial.begin(9600);
  gsm.begin(9600);
  delay(1000);

  // Test AT command
  gsm.println("AT");
  delay(500);
}

void sendSMS(String number, String message) {
  gsm.println("AT+CMGF=1");  // Text mode
  delay(500);
  gsm.print("AT+CMGS="");
  gsm.print(number);
  gsm.println(""");
  delay(500);
  gsm.print(message);
  gsm.write(26);  // Ctrl+Z to send
}

void loop() {
  if (gsm.available()) Serial.write(gsm.read());
  if (Serial.available()) gsm.write(Serial.read());
}

// RFID Tags are passive
// They are read using an RFID reader (RC522)
// Each tag has a unique ID (UID)

// Tag UIDs are typically 4 or 7 bytes
// Example UID: 0x04 0xA3 0x2B 0x1C

// RFID RC522 Reader
#include <SPI.h>
#include <MFRC522.h>

#define SS_PIN 10
#define RST_PIN 9

MFRC522 rfid(SS_PIN, RST_PIN);

void setup() {
  Serial.begin(9600);
  SPI.begin();
  rfid.PCD_Init();
  Serial.println("Scan RFID card...");
}

void loop() {
  if (!rfid.PICC_IsNewCardPresent()) return;
  if (!rfid.PICC_ReadCardSerial()) return;

  Serial.print("UID: ");
  for (byte i = 0; i < rfid.uid.size; i++) {
    Serial.print(rfid.uid.uidByte[i], HEX);
    Serial.print(" ");
  }
  Serial.println();
  rfid.PICC_HaltA();
}

